Exit Body.command:
if (!token) {
  ui.notifications.notify("select a token that the new Intellect Devourer spawns from");
  return;
}

const movePolygon = computeExitBodyCollisionGrid();

const c = token.center;
const s = canvas.scene.dimensions.size;
const exitLocations = [];
for (let i = -1; i <= 1; i++) {
  for (let j = -1; j <= 1; j++) {
    const point = new PIXI.Point(c.x + s * i, c.y + s * j);
    if (!movePolygon.contains(point.x, point.y)) continue;
    if (canvas.tokens.placeables.filter((token) => token.bounds.contains(point.x, point.y)).length > 0) continue;
    const [x0, y0] = canvas.grid.getTopLeft(point.x, point.y);
    exitLocations.push(new PIXI.Point(x0, y0));
  }
}
if (exitLocations.length === 0) {
  ui.notifications.notify("No space to exit the body");
  return;
}
const roll = (await new Roll(`1d${exitLocations.length} - 1`).evaluate()).total;

await token.actor.update({"system.attributes.hp.value": 0})
await token.actor.toggleStatusEffect('dead', {overlay: true});
const intellectDevourer = fromUuidSync(
  ["K7hvZokBDqu61Sws"].includes(token.actor.id)
    ? "Actor.CILo525fbQw8b4W4"
    : "Actor.hxncLW8a85xWnOLG");
const newToken = await intellectDevourer.getTokenDocument({x: exitLocations[roll].x, y: exitLocations[roll].y});

// handle Vekensvok
if (
  ["ecqOHEl8XRfXrQUj","abBSh56KTwnv53PO","Xrwz0r4y4wKiEZfr","4ws2PCdkV5QVEJ49"]
    .includes(token.actor.id)
) {
  newToken.name = "Tiluatchek"
}

canvas.scene.createEmbeddedDocuments("Token", [newToken]);

function computeExitBodyCollisionGrid() {
  const c = token.center;
  const s = canvas.scene.dimensions.size;

  // Compute a rectangle for the engagement bounds
  const [x0, y0] = canvas.grid.getTopLeft(c.x, c.y);
  const engagementBounds = new PIXI.Rectangle(x0 - s, y0 - s, 3 * s, 3 * s);

  // Compute a movement polygon which excludes impassible walls
  const movePolygon = ClockwiseSweepPolygon.create(c, {
    type: "move",
    boundaryShapes: [engagementBounds]
  });
  return movePolygon;
}

