Turn Skull 1.command:
if (canvas.scene.id !== "zKVyZcQFwXIQoXBq") {
  return;
}
if (!token) {
  ui.notifications.notify("Please select the token that the skull turns towards");
}
const tile = fromUuidSync("Scene.zKVyZcQFwXIQoXBq.Tile.aMLaaJvJ3EuojKhe");

const tileCenter = new PIXI.Point(tile.x + tile.width / 2, tile.y + tile.height / 2);
const tokenCenter = token.bounds.center;
const radian = new Ray(tileCenter, tokenCenter).angle;
const angle = radian === 0 ? 0 : radian > 0 ? (radian / Math.PI) * 180 : 360 - (Math.abs(radian) / Math.PI) * 180;

tile.update({rotation: angle}, {animate: true})

